mapper.select:
	SELECT COALESCE(ALQTY, 0)
    FROM TWORK_INFO_IVATXLCXULC
    WHERE CTKEY   = #{ctkey}
      AND OWKEY   = #{owkey}
      AND IVATKEY = #{ivatkey}
      AND LCKEY   = #{lckey}
      AND ULCKEY  = #{ulckey}

	SELECT IVATSTATUS
    FROM TWORK_INFO_IVATXLCXULC
    WHERE CTKEY   = #{ctkey}
      AND OWKEY   = #{owkey}
      AND IVATKEY = #{ivatkey}
      AND LCKEY   = #{lckey}
      AND ULCKEY  = #{ulckey}

SELECT WKSTATUS
FROM TWORK_MST_LC
WHERE CTKEY = #{ctkey}
  AND LCKEY = #{lckey}

mapper.sql:
SELECT AA.* , COUNT(*)OVER() AS TOTALCOUNT FROM ( SELECT B.PRODUCTLOT ,A.CTKEY ,A.IVATKEY ,A.LCKEY ,A.ULCKEY ,A.OWKEY ,(SELECT OWNAME FROM TWORK_MST_OW OW WHERE OW.OWKEY = A.OWKEY) AS OWNAME ,A.ICKEY ,CASE G.ICUTQTY WHEN 0 THEN 0 ELSE A.TTQTY / G.ICUTQTY END AS TTQTY ,CASE G.ICUTQTY WHEN 0 THEN 0 ELSE A.AVQTY / G.ICUTQTY END AS AVQTY ,CASE G.ICUTQTY WHEN 0 THEN 0 ELSE A.ALQTY / G.ICUTQTY END AS ALQTY ,CASE G.ICUTQTY WHEN 0 THEN 0 ELSE A.PIQTY / G.ICUTQTY END AS PIQTY ,CASE G.ICUTQTY WHEN 0 THEN 0 ELSE A.PAQTY / G.ICUTQTY END AS PAQTY ,CASE G.ICUTQTY WHEN 0 THEN 0 ELSE A.HOQTY / G.ICUTQTY END AS HOQTY ,A.INSERTDATE ,A.INSERTURKEY ,A.UPDATEDATE ,A.UPDATEURKEY ,B.PRODUCTDATE ,B.EXPIREDATE ,B.IBCONFIRMDATE ,B.IVATSTATUS ,A.CTKEY || ';' || 'IVATSTATUS' ||';'|| A.IVATSTATUS AS IVATSTATUS_DESC ,B.ATTRIBUTE1 ,A.CTKEY || ';' || 'ATTRIBUTE1' ||';'|| B.ATTRIBUTE1 AS ATTRIBUTE1_DESC ,B.ATTRIBUTE2 ,A.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| B.ATTRIBUTE2 AS ATTRIBUTE2_DESC ,B.ATTRIBUTE3 ,A.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| B.ATTRIBUTE3 AS ATTRIBUTE3_DESC ,C.ERPSTLC ,CASE WHEN J.LCKEY = A.LCKEY THEN '' ELSE J.LCKEY END AS TO_LCKEY ,'' AS TO_ERPSTLC ,'' AS TO_ULCKEY ,0 AS MV_QTY ,'10' AS MV_REASONTYPE ,D.USE_ERPSTLC ,E.UOM ,A.CTKEY || ';' || 'ICUTTYPE' ||';'|| E.UOM AS UOM_DESC ,E.ICUTKEY ,G.ICUTQTY ,E.ICNAME ,E.SPEC ,C.MVREASON_YN ,H.ACKEY ,H.ACNAME ,I.URKEY ,I.URKEY AS URKEY_DESC ,K.ZNKEY ,C.LCSTORTYPE ,A.CTKEY ||';'||'LCSTORTYPE'||';'|| C.LCSTORTYPE AS LCSTORTYPE_DESC ,C.WKSTATUS ,A.CTKEY ||';'||'LC_WKSTATUS'||';'|| C.WKSTATUS AS WKSTATUS_DESC ,C.LCHOLDTYPE ,E.SHELFLIFECODETYPE ,E.LOGGRPCD ,A.CTKEY || ';' || 'LOGGRPCD' || ';' || E.LOGGRPCD AS LOGGRPCD_DESC FROM TWORK_INFO_IVATXLCXULC A INNER JOIN TWORK_INFO_IVAT B ON A.CTKEY = B.CTKEY AND A.IVATKEY = B.IVATKEY INNER JOIN TWORK_MST_LC C ON A.CTKEY = C.CTKEY AND A.LCKEY = C.LCKEY INNER JOIN TWORK_MST_OW D ON A.OWKEY = D.OWKEY INNER JOIN TWORK_MST_IC E ON B.CTKEY = E.CTKEY AND B.OWKEY = E.OWKEY AND B.ICKEY = E.ICKEY INNER JOIN TWORK_MST_AR L ON C.CTKEY = L.CTKEY AND C.ARKEY = L.ARKEY LEFT JOIN TWORK_MST_ICUT F ON E.OWKEY = F.OWKEY AND E.CTKEY = F.CTKEY AND E.ICUTKEY = F.ICUTKEY LEFT JOIN TWORK_MST_ICUTXTYPE G ON E.OWKEY = G.OWKEY AND E.CTKEY = G.CTKEY AND E.ICUTKEY = G.ICUTKEY AND E.UOM = G.ICUTTYPE LEFT JOIN TWORK_MST_AC H ON E.CTKEY = H.CTKEY AND E.ACKEY = H.ACKEY AND E.OWKEY = H.OWKEY LEFT JOIN TWORK_MST_ACXUR I ON E.CTKEY = I.CTKEY AND E.ACKEY = I.ACKEY AND E.LOGGRPCD = I.LOGGRPCD AND E.OWKEY = I.OWKEY LEFT JOIN TWORK_MST_LCXIC J ON J.CTKEY = E.CTKEY AND J.OWKEY = E.OWKEY AND J.ICKEY = E.ICKEY LEFT JOIN TWORK_MST_ZN K ON C.CTKEY = K.CTKEY AND L.ZNKEY = K.ZNKEY WHERE F.CLOSDATE >= #{sysdate} AND A.CTKEY = #{ctkey} AND A.TTQTY > 0
AND #{SEARCH_CONDITION}
) AA

SELECT * FROM ( SELECT COUNT(*)OVER() AS TOTALCOUNT ,A.ZNKEY ,E.LOGGRPCD ,D.LCKEY ,'' AS TO_LCKEY ,D.ULCKEY ,A.CTKEY ,E.UOM ,D.ICKEY ,E.ICNAME ,E.ICUTKEY ,E.SPEC ,D.CTKEY || ';' || 'ICUTTYPE' ||';'|| E.UOM AS UOM_DESC ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.TTQTY / F.ICUTQTY END AS TTQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.AVQTY / F.ICUTQTY END AS AVQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.ALQTY / F.ICUTQTY END AS ALQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.PIQTY / F.ICUTQTY END AS PIQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.PAQTY / F.ICUTQTY END AS PAQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.HOQTY / F.ICUTQTY END AS HOQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.AVQTY / F.ICUTQTY END + CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.HOQTY / F.ICUTQTY END AS ORAVQTY ,0 AS MV_QTY ,D.OWKEY ,(SELECT OWNAME FROM TWORK_MST_OW OW WHERE OW.OWKEY = D.OWKEY) AS OWNAME ,C.PRODUCTLOT ,C.PRODUCTDATE ,C.EXPIREDATE ,C.IBCONFIRMDATE ,D.IVATKEY ,C.IVATSTATUS ,A.CTKEY || ';' || 'IVATSTATUS' ||';'|| C.IVATSTATUS AS IVATSTATUS_DESC ,C.ATTRIBUTE1 ,D.CTKEY || ';' || 'ATTRIBUTE1' ||';'|| C.ATTRIBUTE1 AS ATTRIBUTE1_DESC ,C.ATTRIBUTE2 ,D.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| C.ATTRIBUTE2 AS ATTRIBUTE2_DESC ,C.ATTRIBUTE3 ,D.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| C.ATTRIBUTE3 AS ATTRIBUTE3_DESC ,B.ERPSTLC ,'10' AS MV_REASONTYPE ,D.INSERTDATE ,D.INSERTURKEY ,(SELECT URNM FROM TADMIN_MST_UR WHERE URKEY = D.INSERTURKEY) INSERTURNM ,D.UPDATEDATE ,D.UPDATEURKEY ,(SELECT URNM FROM TADMIN_MST_UR WHERE URKEY = D.UPDATEURKEY) UPDATEURNM ,F.ICUTTYPE ,C.ATTRIBUTE7 FROM TWORK_MST_AR A INNER JOIN TWORK_MST_LC B ON A.CTKEY = B.CTKEY AND A.ARKEY = B.ARKEY INNER JOIN TWORK_INFO_IVAT C ON A.CTKEY = C.CTKEY INNER JOIN TWORK_INFO_IVATXLCXULC D ON C.CTKEY = D.CTKEY AND C.IVATKEY = D.IVATKEY AND B.LCKEY = D.LCKEY INNER JOIN TWORK_MST_IC E ON C.OWKEY = E.OWKEY AND C.CTKEY = E.CTKEY AND C.ICKEY = E.ICKEY LEFT JOIN TWORK_MST_ICUTXTYPE F ON C.OWKEY = F.OWKEY AND E.CTKEY = F.CTKEY AND E.ICUTKEY = F.ICUTKEY AND E.UOM = F.ICUTTYPE WHERE A.WRHOUS_SE = 'GNRL' --일반창고 AND C.ATTRIBUTE2 = '1' AND D.TTQTY > 0 AND (D.IVATSTATUS = '10' AND D.AVQTY > 0 OR D.IVATSTATUS = '30' AND D.HOQTY > 0 ) AND A.CTKEY = #{ctkey}
AND #{SEARCH_CONDITION}
)

SELECT AA.* , COUNT(*)OVER() AS TOTALCOUNT FROM ( SELECT A.ZNKEY ,E.LOGGRPCD ,D.LCKEY ,'' AS TO_LCKEY ,D.ULCKEY ,A.CTKEY ,E.UOM ,D.ICKEY ,E.ICUTKEY ,E.ICNAME ,E.SPEC ,D.CTKEY || ';' || 'ICUTTYPE' ||';'|| E.UOM AS UOM_DESC ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.TTQTY / F.ICUTQTY END AS TTQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.AVQTY / F.ICUTQTY END AS AVQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.ALQTY / F.ICUTQTY END AS ALQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.PIQTY / F.ICUTQTY END AS PIQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.PAQTY / F.ICUTQTY END AS PAQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.HOQTY / F.ICUTQTY END AS HOQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.AVQTY / F.ICUTQTY END + CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.HOQTY / F.ICUTQTY END AS ORAVQTY ,0 AS MV_QTY ,D.OWKEY ,(SELECT OWNAME FROM TWORK_MST_OW OW WHERE OW.OWKEY = D.OWKEY) AS OWNAME ,C.PRODUCTLOT ,C.PRODUCTDATE ,C.EXPIREDATE ,C.IBCONFIRMDATE ,D.IVATKEY ,C.IVATSTATUS ,A.CTKEY || ';' || 'IVATSTATUS' ||';'|| C.IVATSTATUS AS IVATSTATUS_DESC ,C.ATTRIBUTE1 ,D.CTKEY || ';' || 'ATTRIBUTE1' ||';'|| C.ATTRIBUTE1 AS ATTRIBUTE1_DESC ,C.ATTRIBUTE2 ,D.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| C.ATTRIBUTE2 AS ATTRIBUTE2_DESC ,C.ATTRIBUTE3 ,D.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| C.ATTRIBUTE3 AS ATTRIBUTE3_DESC ,B.ERPSTLC ,D.INSERTDATE ,D.INSERTURKEY ,(SELECT URNM FROM TADMIN_MST_UR WHERE URKEY = D.INSERTURKEY) INSERTURNM ,D.UPDATEDATE ,D.UPDATEURKEY ,(SELECT URNM FROM TADMIN_MST_UR WHERE URKEY = D.UPDATEURKEY) UPDATEURNM ,F.ICUTTYPE ,'N' AS EMRGNCY_OB_YN ,C.ATTRIBUTE7 FROM TWORK_MST_AR A INNER JOIN TWORK_MST_LC B ON A.CTKEY = B.CTKEY AND A.ARKEY = B.ARKEY INNER JOIN TWORK_INFO_IVAT C ON A.CTKEY = C.CTKEY INNER JOIN TWORK_INFO_IVATXLCXULC D ON C.CTKEY = D.CTKEY AND C.IVATKEY = D.IVATKEY AND B.LCKEY = D.LCKEY INNER JOIN TWORK_MST_IC E ON C.OWKEY = E.OWKEY AND C.CTKEY = E.CTKEY AND C.ICKEY = E.ICKEY LEFT JOIN TWORK_MST_ICUTXTYPE F ON C.OWKEY = F.OWKEY AND E.CTKEY = F.CTKEY AND E.ICUTKEY = F.ICUTKEY AND E.UOM = F.ICUTTYPE WHERE A.WRHOUS_SE = 'ATMC' --자동창고 AND C.ATTRIBUTE2 = '1' AND D.AVQTY > 0 AND D.IVATSTATUS = '10' AND A.CTKEY = #{ctkey}
AND #{SEARCH_CONDITION}
) AA

