mapper.sql:
SELECT * FROM ( SELECT COUNT(*)OVER() AS TOTALCOUNT ,A.ZNKEY ,E.LOGGRPCD ,D.LCKEY ,'' AS TO_LCKEY ,D.ULCKEY ,A.CTKEY ,E.UOM ,D.ICKEY ,E.ICNAME ,E.ICUTKEY ,E.SPEC ,D.CTKEY || ';' || 'ICUTTYPE' ||';'|| E.UOM AS UOM_DESC ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.TTQTY / F.ICUTQTY END AS TTQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.AVQTY / F.ICUTQTY END AS AVQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.ALQTY / F.ICUTQTY END AS ALQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.PIQTY / F.ICUTQTY END AS PIQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.PAQTY / F.ICUTQTY END AS PAQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.HOQTY / F.ICUTQTY END AS HOQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.AVQTY / F.ICUTQTY END + CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.HOQTY / F.ICUTQTY END AS ORAVQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.AVQTY / F.ICUTQTY END AS MV_QTY ,D.OWKEY ,(SELECT OWNAME FROM TWORK_MST_OW OW WHERE OW.OWKEY = D.OWKEY) AS OWNAME ,C.PRODUCTLOT ,C.PRODUCTDATE ,C.EXPIREDATE ,C.IBCONFIRMDATE ,D.IVATKEY ,C.IVATSTATUS ,A.CTKEY || ';' || 'IVATSTATUS' ||';'|| C.IVATSTATUS AS IVATSTATUS_DESC ,C.ATTRIBUTE1 ,D.CTKEY || ';' || 'ATTRIBUTE1' ||';'|| C.ATTRIBUTE1 AS ATTRIBUTE1_DESC ,C.ATTRIBUTE2 ,D.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| C.ATTRIBUTE2 AS ATTRIBUTE2_DESC ,C.ATTRIBUTE3 ,D.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| C.ATTRIBUTE3 AS ATTRIBUTE3_DESC ,B.ERPSTLC ,'10' AS MV_REASONTYPE ,D.INSERTDATE ,D.INSERTURKEY ,D.UPDATEDATE ,D.UPDATEURKEY ,F.ICUTTYPE FROM TWORK_MST_AR A ,TWORK_MST_LC B ,TWORK_INFO_IVAT C ,TWORK_INFO_IVATXLCXULC D ,TWORK_MST_IC E ,TWORK_MST_ICUTXTYPE F INNER JOIN TWORK_MST_LC B ON A.CTKEY = B.CTKEY AND A.ARKEY = B.ARKEY INNER JOIN TWORK_INFO_IVAT C ON A.CTKEY = C.CTKEY INNER JOIN TWORK_INFO_IVATXLCXULC D ON C.CTKEY = D.CTKEY AND C.IVATKEY = D.IVATKEY AND B.LCKEY = D.LCKEY INNER JOIN TWORK_MST_IC E ON C.OWKEY = E.OWKEY AND C.CTKEY = E.CTKEY AND C.ICKEY = E.ICKEY LEFT JOIN TWORK_MST_ICUTXTYPE F ON C.OWKEY = F.OWKEY AND E.CTKEY = F.CTKEY AND E.ICUTKEY = F.ICUTKEY AND E.UOM = F.ICUTTYPE WHERE A.WRHOUS_SE = 'GNRL' --일반창고 AND C.ATTRIBUTE2 = '2' AND D.TTQTY > 0 AND (D.IVATSTATUS = '10' AND D.AVQTY > 0 OR D.IVATSTATUS = '30' AND D.HOQTY > 0 ) AND A.CTKEY = #{ctkey}
AND #{SEARCH_CONDITION}
)

SELECT * FROM ( SELECT COUNT(*)OVER() AS TOTALCOUNT ,A.ZNKEY ,E.LOGGRPCD ,D.LCKEY ,'' AS TO_LCKEY ,D.ULCKEY ,A.CTKEY ,E.UOM ,D.ICKEY ,E.ICUTKEY ,E.ICNAME ,E.SPEC ,D.CTKEY || ';' || 'ICUTTYPE' ||';'|| E.UOM AS UOM_DESC ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.TTQTY / F.ICUTQTY END AS TTQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.AVQTY / F.ICUTQTY END AS AVQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.ALQTY / F.ICUTQTY END AS ALQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.PIQTY / F.ICUTQTY END AS PIQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.PAQTY / F.ICUTQTY END AS PAQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.HOQTY / F.ICUTQTY END AS HOQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.AVQTY / F.ICUTQTY END + CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.HOQTY / F.ICUTQTY END AS ORAVQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.AVQTY / F.ICUTQTY END AS MV_QTY ,D.OWKEY ,(SELECT OWNAME FROM TWORK_MST_OW OW WHERE OW.OWKEY = D.OWKEY) AS OWNAME ,C.PRODUCTLOT ,C.PRODUCTDATE ,C.EXPIREDATE ,C.IBCONFIRMDATE ,D.IVATKEY ,C.IVATSTATUS ,A.CTKEY || ';' || 'IVATSTATUS' ||';'|| C.IVATSTATUS AS IVATSTATUS_DESC ,C.ATTRIBUTE1 ,D.CTKEY || ';' || 'ATTRIBUTE1' ||';'|| C.ATTRIBUTE1 AS ATTRIBUTE1_DESC ,C.ATTRIBUTE2 ,D.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| C.ATTRIBUTE2 AS ATTRIBUTE2_DESC ,C.ATTRIBUTE3 ,D.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| C.ATTRIBUTE3 AS ATTRIBUTE3_DESC ,B.ERPSTLC ,D.INSERTDATE ,D.INSERTURKEY ,D.UPDATEDATE ,D.UPDATEURKEY ,F.ICUTTYPE ,'N' AS EMRGNCY_OB_YN FROM TWORK_MST_AR A ,TWORK_MST_LC B ,TWORK_INFO_IVAT C ,TWORK_INFO_IVATXLCXULC D ,TWORK_MST_IC E ,TWORK_MST_ICUTXTYPE F INNER JOIN TWORK_MST_LC B ON A.CTKEY = B.CTKEY AND A.ARKEY = B.ARKEY INNER JOIN TWORK_INFO_IVAT C ON A.CTKEY = C.CTKEY INNER JOIN TWORK_INFO_IVATXLCXULC D ON C.CTKEY = D.CTKEY AND C.IVATKEY = D.IVATKEY AND B.LCKEY = D.LCKEY INNER JOIN TWORK_MST_IC E ON C.OWKEY = E.OWKEY AND C.CTKEY = E.CTKEY AND C.ICKEY = E.ICKEY LEFT JOIN TWORK_MST_ICUTXTYPE F ON C.OWKEY = F.OWKEY AND E.CTKEY = F.CTKEY AND E.ICUTKEY = F.ICUTKEY AND E.UOM = F.ICUTTYPE WHERE A.WRHOUS_SE = 'ATMC' --자동창고 AND C.ATTRIBUTE2 = '2' AND D.AVQTY > 0 AND D.IVATSTATUS = '10' AND A.CTKEY = #{ctkey}
AND #{SEARCH_CONDITION}
)

SELECT * FROM ( SELECT COUNT(*)OVER() AS TOTALCOUNT ,A.ZNKEY ,E.LOGGRPCD ,D.LCKEY ,'' AS TO_LCKEY ,D.ULCKEY ,A.CTKEY ,E.UOM ,D.ICKEY ,E.ICUTKEY ,E.ICNAME ,E.SPEC ,D.CTKEY || ';' || 'ICUTTYPE' ||';'|| E.UOM AS UOM_DESC ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.AVQTY / F.ICUTQTY END AS AVQTY ,CASE F.ICUTQTY WHEN 0 THEN 0 ELSE D.AVQTY / F.ICUTQTY END AS MV_QTY ,D.OWKEY ,(SELECT OWNAME FROM TWORK_MST_OW OW WHERE OW.OWKEY = D.OWKEY) AS OWNAME ,C.PRODUCTLOT ,C.PRODUCTDATE ,C.EXPIREDATE ,C.IBCONFIRMDATE ,D.IVATKEY ,C.IVATSTATUS ,A.CTKEY || ';' || 'IVATSTATUS' ||';'|| C.IVATSTATUS AS IVATSTATUS_DESC ,C.ATTRIBUTE1 ,D.CTKEY || ';' || 'ATTRIBUTE1' ||';'|| C.ATTRIBUTE1 AS ATTRIBUTE1_DESC ,C.ATTRIBUTE2 ,D.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| C.ATTRIBUTE2 AS ATTRIBUTE2_DESC ,C.ATTRIBUTE3 ,D.CTKEY || ';' || 'ATTRIBUTE2' ||';'|| C.ATTRIBUTE3 AS ATTRIBUTE3_DESC ,B.ERPSTLC ,D.INSERTDATE ,D.INSERTURKEY ,D.UPDATEDATE ,D.UPDATEURKEY ,F.ICUTTYPE FROM TWORK_MST_AR A ,TWORK_MST_LC B ,TWORK_INFO_IVAT C ,TWORK_INFO_IVATXLCXULC D ,TWORK_MST_IC E ,TWORK_MST_ICUTXTYPE F INNER JOIN TWORK_MST_LC B ON A.CTKEY = B.CTKEY AND A.ARKEY = B.ARKEY INNER JOIN TWORK_INFO_IVAT C ON A.CTKEY = C.CTKEY INNER JOIN TWORK_INFO_IVATXLCXULC D ON C.CTKEY = D.CTKEY AND C.IVATKEY = D.IVATKEY AND B.LCKEY = D.LCKEY INNER JOIN TWORK_MST_IC E ON C.OWKEY = E.OWKEY AND C.CTKEY = E.CTKEY AND C.ICKEY = E.ICKEY LEFT JOIN TWORK_MST_ICUTXTYPE F ON C.OWKEY = F.OWKEY AND E.CTKEY = F.CTKEY AND E.ICUTKEY = F.ICUTKEY AND E.UOM = F.ICUTTYPE WHERE A.WRHOUS_SE = 'ATMC' --자동창고 AND D.AVQTY > 0 AND D.IVATSTATUS = '10' AND A.CTKEY = #{ctkey}
AND #{SEARCH_CONDITION}
)
